import{_ as o,o as a,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"44. Compassionate Leave","description":"","frontmatter":{"title":"44. Compassionate Leave","eba":"Mental Health Services 2024-2028","topics":["leave","compassionate-leave","preliminary","definitions"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/44-compassionate-leave.md","filePath":"ebas/mental-health/common-terms/leave/44-compassionate-leave.md"}'),n={name:"ebas/mental-health/common-terms/leave/44-compassionate-leave.md"};function r(i,e,l,p,m,h){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_44-compassionate-leave" tabindex="-1">44. Compassionate Leave <a class="header-anchor" href="#_44-compassionate-leave" aria-label="Permalink to &quot;44. Compassionate Leave&quot;">​</a></h1><p><strong>44.1</strong> An Employer may use its discretion to grant paid and/or unpaid compassionate leave to relatives not covered by the definition of Immediate Family.</p><p><strong>44.2</strong> What is Compassionate Leave? Compassionate leave will be available under this clause 44 to an Employee for each occasion (a “permissible occasion”) when:</p><p><strong>(a)</strong> a member of the Employee’s Immediate Family or household:</p><p><strong>(i)</strong> contracts or develops a personal illness or sustains a personal injury that poses a serious threat to their life; or</p><p><strong>(ii)</strong> dies;</p><p><strong>(b)</strong> an Employee experiences pregnancy loss, where the pregnancy comes to an end before 20 weeks’ gestation. For the removal of doubt, an Employee who is the partner of a person who experiences pregnancy loss will also be entitled to the equivalent period of compassionate leave; or</p><p><strong>(c)</strong> A Stillborn Child is born, where the Stillborn Child would have been a member of the Employee’s Immediate Family, or a member of the Employee’s household, if the Stillborn Child had been born alive. Note: An Employee may be entitled to a period of paid special leave if their pregnancy terminates at or after the completion of 20 weeks’ gestation or if the Employee gives birth but the baby subsequently dies – see <a href="/eba/ebas/mental-health/common-terms/leave/50-parental-leave.html">clause 50.10</a>(b)(i).</p><p><strong>44.3</strong> If the permissible occasion is the contraction or development of a personal illness, or the sustaining of a personal injury, the Employee may take the compassionate leave for that occasion at any time while the illness or injury persists.</p><p><strong>44.4</strong> Employees other than casual Employees The provisions of clauses 44.5 to 44.7 apply to all Employees other than casual Employees. The entitlements of casual Employees are set out in clause 44.8.</p><p><strong>44.5</strong> An Employee is entitled to up to 4 ordinary days’ paid leave, on each permissible occasion.</p><p><strong>44.6</strong> An Employee may take compassionate leave for a permissible occasion as:</p><p><strong>(a)</strong> a single continuous 4-day period; or</p><p><strong>(b)</strong> 2 separate periods of 2 days each; or</p><p><strong>(c)</strong> any separate periods to which the Employee and Employer agree.</p><p><strong>44.7</strong> Employee may take unpaid additional compassionate leave by agreement with the Employer.</p><p><strong>44.8</strong> Casual Employees Subject to the evidence requirements described at clause, a casual Employee is entitled to 4 days unpaid compassionate leave on each permissible occasion. Unpaid compassion leave under this subclause may be taken as:</p><p><strong>(a)</strong> a single continuous period,</p><p><strong>(b)</strong> 2 separate periods of 2 days each, or</p><p><strong>(c)</strong> any separate periods to which the Employee and Employer agree.</p><p><strong>44.9</strong> Notice Requirements</p><p><strong>(a)</strong> An Employee must give their Employer notice of the taking of leave under this clause by the Employee.</p><p><strong>(b)</strong> The notice:</p><p><strong>(i)</strong> must be given to the Employer as soon as practicable (which may be a time after the leave has started); and</p><p><strong>(ii)</strong> must advise the Employer of the period, or expected period, of the leave.</p><p><strong>44.10</strong> Evidence – all Employees An Employee who has given their Employer notice of the taking of leave under this Division must, if required by the Employer, give the Employer evidence that would satisfy a reasonable person.</p><p>Plain language terms: bereavement leave, funeral leave, death of family.</p>',27)])])}const g=o(n,[["render",r]]);export{d as __pageData,g as default};
